DROP TABLE IF EXISTS `adjustment_events`;
CREATE TABLE `adjustment_events` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `product_id` int(11) unsigned NOT NULL,
  `event_type` enum('Damage','Refund','Theft','Return','Other') NOT NULL,
  `quantity` decimal(15,2) NOT NULL,
  `unit_cost` decimal(15,2) DEFAULT NULL,
  `total_value` decimal(15,2) DEFAULT NULL,
  `currency` enum('LRD','USD') NOT NULL DEFAULT 'LRD',
  `reference` varchar(100) DEFAULT NULL,
  `description` text DEFAULT NULL,
  `adjust_stock` tinyint(1) NOT NULL DEFAULT 1,
  `event_date` datetime NOT NULL,
  `related_sale_id` int(11) unsigned DEFAULT NULL,
  `related_production_job_id` int(11) unsigned DEFAULT NULL,
  `customer_id` int(11) unsigned DEFAULT NULL,
  `created_by` int(11) unsigned NOT NULL,
  `updated_by` int(11) unsigned DEFAULT NULL,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  `deleted_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `adjustment_events_customer_id_foreign` (`customer_id`),
  KEY `adjustment_events_created_by_foreign` (`created_by`),
  KEY `product_id` (`product_id`),
  KEY `event_type` (`event_type`),
  KEY `event_date` (`event_date`),
  KEY `idx_adj_sale` (`related_sale_id`),
  KEY `idx_adj_job` (`related_production_job_id`),
  KEY `idx_adj_date` (`event_date`),
  KEY `idx_adj_product` (`product_id`),
  KEY `idx_adj_created` (`created_at`),
  CONSTRAINT `adjustment_events_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `adjustment_events_customer_id_foreign` FOREIGN KEY (`customer_id`) REFERENCES `customers` (`id`) ON DELETE CASCADE ON UPDATE SET NULL,
  CONSTRAINT `adjustment_events_product_id_foreign` FOREIGN KEY (`product_id`) REFERENCES `products` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

