DROP TABLE IF EXISTS `production_categories`;
CREATE TABLE `production_categories` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `category_name` varchar(100) NOT NULL,
  `description` text DEFAULT NULL,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  `deleted_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `category_name` (`category_name`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

INSERT INTO `production_categories` (`id`, `category_name`, `description`, `created_at`, `updated_at`, `deleted_at`) VALUES ('1', 'Heat Pressing (only)', 'Those who bring printout to be heatpressed only', '2026-04-14 01:13:20', '2026-04-14 01:13:20', NULL);

DROP TABLE IF EXISTS `production_job_items`;
CREATE TABLE `production_job_items` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `production_job_id` int(11) unsigned NOT NULL,
  `item_id` int(11) unsigned NOT NULL,
  `quantity_required` decimal(10,2) NOT NULL DEFAULT 0.00,
  `quantity_used` decimal(10,2) NOT NULL DEFAULT 0.00,
  `unit_cost` decimal(10,2) NOT NULL DEFAULT 0.00,
  `total_cost` decimal(10,2) NOT NULL DEFAULT 0.00,
  `notes` text DEFAULT NULL,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  `deleted_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

DROP TABLE IF EXISTS `production_jobs`;
CREATE TABLE `production_jobs` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `job_reference` varchar(100) NOT NULL,
  `job_name` varchar(255) NOT NULL,
  `customer_id` int(11) unsigned DEFAULT NULL,
  `production_date` date NOT NULL,
  `production_category_id` int(11) unsigned DEFAULT NULL,
  `quantity_produced` decimal(15,2) NOT NULL DEFAULT 0.00,
  `total_material_cost` decimal(15,2) NOT NULL DEFAULT 0.00,
  `currency` enum('LRD','USD') NOT NULL DEFAULT 'LRD',
  `exchange_rate` decimal(10,4) DEFAULT NULL,
  `notes` text DEFAULT NULL,
  `status` enum('Draft','Completed','Cancelled') NOT NULL DEFAULT 'Draft',
  `payment_status` enum('Unpaid','Partially Paid','Paid') DEFAULT 'Unpaid',
  `amount_paid` decimal(15,2) DEFAULT 0.00,
  `payment_date` date DEFAULT NULL,
  `created_by` int(11) unsigned NOT NULL,
  `updated_by` int(11) unsigned DEFAULT NULL,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  `deleted_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `job_reference` (`job_reference`),
  KEY `production_jobs_created_by_foreign` (`created_by`),
  KEY `production_jobs_updated_by_foreign` (`updated_by`),
  CONSTRAINT `production_jobs_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `production_jobs_updated_by_foreign` FOREIGN KEY (`updated_by`) REFERENCES `users` (`id`) ON DELETE CASCADE ON UPDATE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

INSERT INTO `production_jobs` (`id`, `job_reference`, `job_name`, `customer_id`, `production_date`, `production_category_id`, `quantity_produced`, `total_material_cost`, `currency`, `exchange_rate`, `notes`, `status`, `payment_status`, `amount_paid`, `payment_date`, `created_by`, `updated_by`, `created_at`, `updated_at`, `deleted_at`) VALUES ('2', 'JOB-202604-0001', 'Tshirt printing', '2', '2026-04-14', NULL, '25.00', '5000.00', 'LRD', NULL, 'the man brough his own heat sublimation and other items - we only charged for heat pressing', 'Draft', 'Partially Paid', '1500.00', NULL, '1', '1', '2026-04-14 01:25:35', '2026-04-14 02:36:33', NULL);

DROP TABLE IF EXISTS `production_materials`;
CREATE TABLE `production_materials` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `production_job_id` int(11) unsigned NOT NULL,
  `product_id` int(11) unsigned NOT NULL,
  `quantity_used` decimal(15,2) NOT NULL,
  `unit_cost` decimal(15,2) NOT NULL,
  `total_cost` decimal(15,2) NOT NULL,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `production_job_id` (`production_job_id`),
  KEY `product_id` (`product_id`),
  CONSTRAINT `production_materials_product_id_foreign` FOREIGN KEY (`product_id`) REFERENCES `products` (`id`) ON DELETE CASCADE,
  CONSTRAINT `production_materials_production_job_id_foreign` FOREIGN KEY (`production_job_id`) REFERENCES `production_jobs` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

INSERT INTO `production_materials` (`id`, `production_job_id`, `product_id`, `quantity_used`, `unit_cost`, `total_cost`, `created_at`, `updated_at`) VALUES ('4', '2', '2', '25.00', '200.00', '5000.00', '2026-04-14 02:36:33', '2026-04-14 02:36:33');

DROP TABLE IF EXISTS `products`;
CREATE TABLE `products` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `product_name` varchar(255) NOT NULL,
  `sku` varchar(100) NOT NULL,
  `barcode` varchar(100) DEFAULT NULL,
  `qr_code` text DEFAULT NULL,
  `description` text DEFAULT NULL,
  `category_id` int(11) unsigned NOT NULL,
  `unit_id` int(11) unsigned NOT NULL,
  `supplier_id` int(11) unsigned DEFAULT NULL,
  `purchase_price` decimal(15,2) NOT NULL DEFAULT 0.00,
  `selling_price` decimal(15,2) NOT NULL DEFAULT 0.00,
  `quantity` decimal(15,2) NOT NULL DEFAULT 0.00,
  `minimum_stock` decimal(15,2) NOT NULL DEFAULT 0.00,
  `product_image` varchar(255) DEFAULT NULL,
  `created_by` int(11) unsigned NOT NULL,
  `updated_by` int(11) unsigned DEFAULT NULL,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  `deleted_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `sku` (`sku`),
  UNIQUE KEY `barcode` (`barcode`),
  KEY `products_created_by_foreign` (`created_by`),
  KEY `products_updated_by_foreign` (`updated_by`),
  KEY `category_id` (`category_id`),
  KEY `unit_id` (`unit_id`),
  KEY `supplier_id` (`supplier_id`),
  CONSTRAINT `products_category_id_foreign` FOREIGN KEY (`category_id`) REFERENCES `categories` (`id`) ON DELETE CASCADE,
  CONSTRAINT `products_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `products_supplier_id_foreign` FOREIGN KEY (`supplier_id`) REFERENCES `suppliers` (`id`) ON DELETE CASCADE ON UPDATE SET NULL,
  CONSTRAINT `products_unit_id_foreign` FOREIGN KEY (`unit_id`) REFERENCES `units` (`id`) ON DELETE CASCADE,
  CONSTRAINT `products_updated_by_foreign` FOREIGN KEY (`updated_by`) REFERENCES `users` (`id`) ON DELETE CASCADE ON UPDATE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

