DROP TABLE IF EXISTS `sales`;
CREATE TABLE `sales` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `invoice_number` varchar(100) NOT NULL,
  `customer_id` int(11) unsigned DEFAULT NULL,
  `customer_name` varchar(255) DEFAULT NULL,
  `customer_phone` varchar(50) DEFAULT NULL,
  `customer_email` varchar(255) DEFAULT NULL,
  `sale_date` date NOT NULL,
  `subtotal` decimal(15,2) NOT NULL DEFAULT 0.00,
  `tax` decimal(15,2) NOT NULL DEFAULT 0.00,
  `discount` decimal(15,2) NOT NULL DEFAULT 0.00,
  `total_amount` decimal(15,2) NOT NULL DEFAULT 0.00,
  `currency` enum('LRD','USD') NOT NULL DEFAULT 'LRD',
  `exchange_rate` decimal(10,4) DEFAULT NULL,
  `payment_method` varchar(50) NOT NULL,
  `payment_status` enum('Paid','Unpaid','Partial') NOT NULL DEFAULT 'Unpaid',
  `amount_paid` decimal(15,2) NOT NULL DEFAULT 0.00,
  `balance_due` decimal(15,2) NOT NULL DEFAULT 0.00,
  `notes` text DEFAULT NULL,
  `qr_code` text DEFAULT NULL,
  `created_by` int(11) unsigned NOT NULL,
  `updated_by` int(11) unsigned DEFAULT NULL,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  `deleted_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `invoice_number` (`invoice_number`),
  KEY `sales_customer_id_foreign` (`customer_id`),
  KEY `sales_created_by_foreign` (`created_by`),
  KEY `sales_updated_by_foreign` (`updated_by`),
  CONSTRAINT `sales_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `sales_customer_id_foreign` FOREIGN KEY (`customer_id`) REFERENCES `customers` (`id`) ON DELETE CASCADE ON UPDATE SET NULL,
  CONSTRAINT `sales_updated_by_foreign` FOREIGN KEY (`updated_by`) REFERENCES `users` (`id`) ON DELETE CASCADE ON UPDATE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

INSERT INTO `sales` (`id`, `invoice_number`, `customer_id`, `customer_name`, `customer_phone`, `customer_email`, `sale_date`, `subtotal`, `tax`, `discount`, `total_amount`, `currency`, `exchange_rate`, `payment_method`, `payment_status`, `amount_paid`, `balance_due`, `notes`, `qr_code`, `created_by`, `updated_by`, `created_at`, `updated_at`, `deleted_at`) VALUES ('1', 'INV-202604-0001', NULL, 'Walk-in Customer', NULL, NULL, '2026-04-13', '300.00', '0.00', '0.00', '300.00', 'USD', '1.0000', 'Cash', 'Partial', '200.00', '100.00', '', NULL, '1', '1', '2026-04-13 16:14:46', '2026-04-14 02:26:45', NULL);

DROP TABLE IF EXISTS `stock_movements`;
CREATE TABLE `stock_movements` (
  `id` int(11) unsigned NOT NULL AUTO_INCREMENT,
  `product_id` int(11) unsigned NOT NULL,
  `movement_type` enum('Purchase','Sale','Production','Adjustment') NOT NULL,
  `reference_type` varchar(50) NOT NULL,
  `reference_id` int(11) unsigned NOT NULL,
  `quantity` decimal(15,2) NOT NULL,
  `previous_quantity` decimal(15,2) NOT NULL,
  `new_quantity` decimal(15,2) NOT NULL,
  `unit_price` decimal(15,2) DEFAULT NULL,
  `total_value` decimal(15,2) DEFAULT NULL,
  `notes` text DEFAULT NULL,
  `currency` enum('LRD','USD') NOT NULL DEFAULT 'LRD',
  `exchange_rate` decimal(10,4) DEFAULT NULL,
  `created_by` int(11) unsigned NOT NULL,
  `created_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `stock_movements_created_by_foreign` (`created_by`),
  KEY `product_id` (`product_id`),
  KEY `reference_type_reference_id` (`reference_type`,`reference_id`),
  CONSTRAINT `stock_movements_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `stock_movements_product_id_foreign` FOREIGN KEY (`product_id`) REFERENCES `products` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=13 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

